patch:
diff --git a/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp b/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
index 6babfd1eee91..14c8ff5f0bc8 100644
--- a/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
+++ b/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
@@ -7284,11 +7284,22 @@ planContainsAdditionalSimplifications(VPlan &Plan, ElementCount VF,
   // Return true if the loop contains any instructions that are not also part of
   // the VPlan or are skipped for VPlan-based cost computations. This indicates
   // that the VPlan contains extra simplifications.
+  //
+  // Note: Branch instructions (except the latch/backedge) that are not
+  // represented in the VPlan are considered evidence of additional
+  // simplifications, even if they are skipped during VPlan-based cost
+  // computation. This accounts for control-flow simplifications (e.g., constant
+  // conditions) that the legacy cost model does not capture.
   return any_of(
-      TheLoop->blocks(), [&SeenInstrs, VF, &CostCtx, &CM](BasicBlock *BB) {
-        return any_of(*BB, [&SeenInstrs, VF, &CostCtx, &CM](Instruction &I) {
+      TheLoop->blocks(), [&SeenInstrs, VF, &CostCtx, &CM, TheLoop](BasicBlock *BB) {
+        return any_of(*BB, [&SeenInstrs, VF, &CostCtx, &CM, BB, TheLoop](Instruction &I) {
           if (isa<PHINode>(&I))
             return false;
+          // If a non-latch branch is not seen in the VPlan, treat it as an
+          // additional simplification irrespective of skip-cost flags.
+          if (isa<BranchInst>(&I) && BB != TheLoop->getLoopLatch() &&
+              !SeenInstrs.contains(&I))
+            return true;
           return !SeenInstrs.contains(&I) &&
                  !CostCtx.skipCostComputation(&I, true) &&
                  !CM.canTruncateToMinimalBitwidth(&I, VF);

